var copyRandomList = function(head) {
    if (!head) return null;
    let cur = head;
    while (cur) {
        const clone = new Node(cur.val);
        clone.next = cur.next;
        cur.next = clone;
        cur = clone.next;
    }
    cur = head;
    while (cur) {
        if (cur.random) cur.next.random = cur.random.next;
        cur = cur.next.next;
    }
    cur = head;
    const newHead = head.next;
    while (cur) {
        const clone = cur.next;
        cur.next = clone.next;
        clone.next = clone.next ? clone.next.next : null;
        cur = cur.next;
    }
    return newHead;
};
